head.script:
(function(){
  const XHTML_NS = "http://www.w3.org/1999/xhtml";
  const root = document.querySelector("foreignObject").firstElementChild;
  const head = root.querySelector("head");
  const body = root.querySelector("body");
  const originalCreateElement = document.createElement.bind(document);
  const originalCreateElementNS = document.createElementNS.bind(document);
  Object.defineProperty(document, "head", { get() { return head }, configurable: true });
  Object.defineProperty(document, "body", { get() { return body }, configurable: true });
  Object.defineProperty(document, "documentElement", { get() { return root }, configurable: true });
  document.createElement = function(tagName, options){
    if(typeof tagName === "string") return originalCreateElementNS(XHTML_NS, tagName, options);
    return originalCreateElement(tagName, options);
  };
  document.createElementNS = function(ns, name, options){
    if(ns == null || ns === XHTML_NS) return originalCreateElementNS(XHTML_NS, name, options);
    return originalCreateElementNS(ns, name, options);
  };
})();

body.script:
const q = (a) => document.getElementById(a);
const din = q('date');
const wordel = q('word');

function formatDate(date) {
  return new Date(date).toISOString().split('T')[0];
}

function seldate(d) {
  din.value = formatDate(d);
}

function offsetDate(offset) {
  const base = din.value ? new Date(din.value) : new Date();
  seldate(base.getTime() + offset);
}

q('seltoday').onclick = () => seldate(Date.now());
q('yest').onclick = () => offsetDate(-86400000);
q('tom').onclick = () => offsetDate(86400000);

async function fetchWordle(d) {
  try {
    const endpoint = `https://corsproxy.io/?url=https://www.nytimes.com/svc/wordle/v2/${d}.json`;
    const res = await fetch(endpoint);
    if (res.status === 429) throw new Error('Rate limit exceeded.');
    if (res.status === 404) throw new Error('Date not found.');
    if (!res.ok) throw new Error('Fetch failed.');
    const json = await res.json();
    return json.solution;
  } catch(e) {
    return e;
  }
}

q("sub").onclick = async function() {
  const d = din.value;
  if (!d) return alert('Enter a date.');
  const date = new Date(d);
  if (date.getTime() < 1624060800000) return alert("Date must be after 2021-06-19");
  const word = await fetchWordle(d);
  wordel.innerText = word instanceof Error ? 'Error: ' + word.message : word;
};
